def collect_book_ratings(n):
    book_ratings = {}

    for i in range(n):
        book_input = input().strip()
        title, ratings = book_input.split(":")
        ratings_list = [int(r) for r in ratings.split(",")]

        if title in book_ratings:
            book_ratings[title].extend(ratings_list)
        else:
            book_ratings[title] = ratings_list

    return book_ratings

n = int(input())

result = collect_book_ratings(n)

print(result)
